namespace sv_eff7bf27dad04831bf7cc0e06df28b11.Services;

/// <summary>
/// Scoped service (one per circuit) that tracks low-stock alert counts.
/// Components subscribe to <see cref="OnAlertCountChanged"/> to react when
/// new data arrives — regardless of which component triggered the refresh.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    public int CurrentAlertCount { get; private set; }

    /// <summary>
    /// Fired whenever <see cref="CurrentAlertCount"/> changes.
    /// Subscribers MUST wrap StateHasChanged in InvokeAsync because
    /// the timer callback runs on a background thread.
    /// </summary>
    public event Action? OnAlertCountChanged;

    /// <summary>Simulates a database query — returns a random count 0-15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate I/O delay
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Begins polling every <paramref name="intervalSeconds"/> seconds for the
    /// given warehouse. Stops any existing poll first.
    /// </summary>
    public void StartPolling(string warehouseId, int intervalSeconds = 10)
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(intervalSeconds));

        _ = PollLoopAsync(warehouseId, token);
    }

    public void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    /// <summary>Perform a one-off refresh (used on first load / warehouse switch).</summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private async Task PollLoopAsync(string warehouseId, CancellationToken token)
    {
        try
        {
            while (_timer is not null && await _timer.WaitForNextTickAsync(token))
            {
                CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
                OnAlertCountChanged?.Invoke();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on StopPolling / Dispose
        }
    }

    public void Dispose() => StopPolling();
}

