@* Interactive island inside the static layout — handles change events. *@
@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@using sv_eff7bf27dad04831bf7cc0e06df28b11.Services

<select class="form-select form-select-sm w-auto"
        value="@_selectedId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseInfo.All)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private string _selectedId = WarehouseInfo.All[0].Id;

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? WarehouseInfo.All[0].Id;
        var selected = WarehouseInfo.All.First(w => w.Id == _selectedId);

        // Push the new value to every [CascadingParameter] subscriber
        await WarehouseSource.NotifyChangedAsync(
            new WarehouseInfo { Id = selected.Id, Name = selected.Name });
    }
}

@* Displays the current low-stock alert count as a Bootstrap badge. *@
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable
@using sv_eff7bf27dad04831bf7cc0e06df28b11.Services

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill">@AlertService.CurrentAlertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync — the timer fires on a background thread
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable
@using sv_eff7bf27dad04831bf7cc0e06df28b11.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 26rem;">
    <div class="card-body">
        <h5 class="card-title">
            Current Warehouse:
            <strong>@(Warehouse?.Name ?? "—")</strong>
        </h5>

        <p class="card-text mt-3">
            Low-stock alerts:
            @if (AlertService.CurrentAlertCount > 0)
            {
                <span class="badge bg-danger fs-6">@AlertService.CurrentAlertCount items</span>
            }
            else
            {
                <span class="badge bg-success fs-6">None</span>
            }
        </p>

        <p class="text-muted small mb-0">
            Polling every 10 seconds. Last check: @_lastRefresh.ToString("HH:mm:ss")
        </p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private Action? _handler;
    private DateTime _lastRefresh = DateTime.Now;
    private string _currentWarehouseId = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _handler = () => InvokeAsync(() =>
        {
            _lastRefresh = DateTime.Now;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _handler;

        if (Warehouse is not null)
        {
            _currentWarehouseId = Warehouse.Id;
            await AlertService.RefreshAsync(Warehouse.Id);
            AlertService.StartPolling(Warehouse.Id);
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Restart polling when the cascading warehouse value changes
        if (Warehouse is not null && Warehouse.Id != _currentWarehouseId)
        {
            _currentWarehouseId = Warehouse.Id;
            await AlertService.RefreshAsync(Warehouse.Id);
            AlertService.StartPolling(Warehouse.Id);
        }
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
        AlertService.StopPolling();
    }
}

